#!/usr/bin/env bash
# psd.sh — Psd 决策助手 for Figma 转 Photoshop (PSD).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Figma 转 Photoshop (PSD)"
TOPIC="Psd"

usage() {
  cat <<EOF
psd.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./psd.sh             # interactive
  ./psd.sh --dry-run   # walk through but no file
  ./psd.sh --json      # JSON to stdout
  ./psd.sh --explain   # show backing playbook rules + mental models
  ./psd.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Psd 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 若需求是「看着对」而非「改得动」→ 走像素保真路线 → 则 ：单/少帧用 Photopea（开 `.fig` → Save as PSD，先载字体）；逐层栅格（素材库 / Afte
  • 如果 若文件是 Display-P3 而目标 PSD 是 sRGB → 先在 Figma 侧 Convert(保留外观) 再导 → 则 ：永远不要 Assign；两边统一 sRGB IEC61966-2.1；嵌入 PSD Image-Resource ID
  • 如果 若要 CMYK / 16-bit / 印刷 → 交付 RGB，在 Photoshop 里转模式 → 则 ：ag-psd 及所有 OSS 只能写 RGB/8-bit，Figma 本身也是 RGB-only——CMYK 永远是 

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "若需求是「看着对」而非「改得动」→ 走像素保真路线"
  "若文件是 Display-P3 而目标 PSD 是 sRGB → 先在 Figma 侧 Convert(保留外观) 再导出并嵌入 profile"
  "若要 CMYK / 16-bit / 印刷 → 交付 RGB，在 Photoshop 里转模式"
)
declare -a RULE_ACTIONS=(
  "：单/少帧用 Photopea（开 \`.fig\` → Save as PSD，先载字体）；逐层栅格（素材库 / After Effects）用 PNG@2x-4x → PS Place 堆叠。接受矢量→栅格。案例：客户只要在 PS 里调色出图的整屏 → Photopea 直转扁平 PSD 即可，不必折腾可编辑。(evidence: [T02-S012, T02-S026])"
  "：永远不要 Assign；两边统一 sRGB IEC61966-2.1；嵌入 PSD Image-Resource ID 1039。最便宜的高 ROI 保真步骤。案例：一张 P3 的品牌红 banner 直接导成 sRGB 会发灰 → 先 Convert 再导就一致。(evidence: [T04-S008, T04-S015, T02-S005])"
  "：ag-psd 及所有 OSS 只能写 RGB/8-bit，Figma 本身也是 RGB-only——CMYK 永远是 PS 侧的 runtime 步骤。案例：要印刷的海报 → 先出 RGB PSD（Photopea/插件），再在 PS 里 Image▸Mode▸CMYK + 正确 ICC。(evidence: [T02-S011, T04-S019])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "psd-decision"
fi
